USE ROLE SECURITYADMIN;






USE ROLE ACCOUNTADMIN;

-- Optional cleanup to avoid stale state
ALTER USER PIQLENS_APP_USER UNSET RSA_PUBLIC_KEY;
ALTER USER PIQLENS_APP_USER UNSET RSA_PUBLIC_KEY_2;

-- IMPORTANT: paste public key body as a single uninterrupted base64 string
ALTER USER PIQLENS_APP_USER
SET RSA_PUBLIC_KEY = '
';

-- Primary verification
DESC USER PIQLENS_APP_USER;

-- Better parameter check syntax
SHOW PARAMETERS LIKE 'RSA_PUBLIC_KEY%' IN USER PIQLENS_APP_USER;

-- Additional user-level check
SHOW USERS LIKE 'PIQLENS_APP_USER';
ALTER USER PIQLENS_APP_USER
  SET RSA_PUBLIC_KEY = '
';
DESC USER PIQLENS_APP_USER;
SHOW PARAMETERS LIKE 'RSA_PUBLIC_KEY' FOR USER PIQLENS_APP_USER;
SHOW PARAMETERS LIKE 'RSA_PUBLIC_KEY_FP' FOR USER PIQLENS_APP_USER;
SHOW GRANTS TO USER PIQLENS_APP_USER;
SHOW GRANTS OF ROLE PIQLENS_ENGINEER_ROLE;

-- Runtime access validation must be executed while connected as PIQLENS_APP_USER
-- (or another user that actually has PIQLENS_ENGINEER_ROLE assigned).
-- If your worksheet user does not have PIQLENS_ENGINEER_ROLE, do not USE ROLE here.

