DESC USER PIQLENS_APP_USER;
SELECT "property", "value"
FROM TABLE(RESULT_SCAN(LAST_QUERY_ID()))
WHERE "property" ILIKE 'RSA_PUBLIC_KEY%';
SHOW GRANTS TO USER PIQLENS_APP_USER;
SHOW GRANTS OF ROLE PIQLENS_ENGINEER_ROLE;




-- changing the role of the user 
GRANT ROLE PIQLENS_VIEWER_ROLE TO USER PIQLENS_APP_USER;
USE ROLE SECURITYADMIN;
ALTER USER PIQLENS_APP_USER
SET DEFAULT_ROLE = PIQLENS_VIEWER_ROLE;

GRANT ROLE PIQLENS_ADMIN_ROLE TO USER PIQLENS_APP_USER;
ALTER USER PIQLENS_APP_USER
SET DEFAULT_ROLE = PIQLENS_ADMIN_ROLE;
  -- choose desired role

describe user PIQLENS_APP_USER;

  SELECT CURRENT_USER(), CURRENT_ROLE(), CURRENT_WAREHOUSE(), CURRENT_DATABASE(), CURRENT_SCHEMA();